local Settings = {}

ExpConfig = {}

local function init()
    Settings = {}
    local config = FileUtil.getConfigFromCsv("setting/ExpConfig.csv")
    for _, exp in pairs(config) do
        local data = {}
        data.exp_lv = tonumber(exp.exp_lv) or 0
        data.exp_max = exp.exp_max or ""
        data.yaoshi = tonumber(exp.yaoshi) or 0

        data.box_id = tonumber(exp.box_id) or 0
        data.box_num = tonumber(exp.box_num) or 0
        data.box_img = tostring(exp.box_img) or ""

        if data.box_img == "#" then
            data.box_img = ""
        end

        if tostring(exp.dress_id_list) ~= "0" then
            data.dress_id_list = {}
            local dress_id_list = StringUtil.split(tostring(exp.dress_id_list), "#")
            if dress_id_list then
                for i = 1, #dress_id_list do
                    table.insert(data.dress_id_list, tonumber(dress_id_list[i]))
                end
            end
        end

        if tostring(exp.dress_num_list) ~= "0" then
            data.dress_num_list = {}
            local dress_num_list = StringUtil.split(tostring(exp.dress_num_list), "#")
            if dress_num_list then
                for i = 1, #dress_num_list do
                    table.insert(data.dress_num_list, tonumber(dress_num_list[i]))
                end
            end
        end

        if tostring(exp.dress_img_list) ~= "0" then
            data.dress_img_list = {}
            local dress_img_list = StringUtil.split(tostring(exp.dress_img_list), "#")
            if dress_img_list then
                for i = 1, #dress_img_list do
                    table.insert(data.dress_img_list, tonumber(dress_img_list[i]))
                end
            end
        end

        if tostring(exp.rune_id_list) ~= "0" then
            data.rune_id_list = {}
            local rune_id_list = StringUtil.split(tostring(exp.rune_id_list), "#")
            if rune_id_list then
                for i = 1, #rune_id_list do
                    table.insert(data.rune_id_list, tonumber(rune_id_list[i]))
                end
            end
        end

        if tostring(exp.rune_num_list) ~= "0" then
            data.rune_num_list = {}
            local rune_num_list = StringUtil.split(tostring(exp.rune_num_list), "#")
            if rune_num_list then
                for i = 1, #rune_num_list do
                    table.insert(data.rune_num_list, tonumber(rune_num_list[i]))
                end
            end
        end

        if tostring(exp.rune_img_list) ~= "0" then
            data.rune_img_list = {}
            local rune_img_list = StringUtil.split(tostring(exp.rune_img_list), "#")
            if rune_img_list then
                for i = 1, #rune_img_list do
                    table.insert(data.rune_img_list, tostring(rune_img_list[i]))
                end
            end
        end

        table.insert(Settings, data)
    end
    table.sort(Settings,function (a, b)
        return a.exp_lv < b.exp_lv
    end)
end

init()

function ExpConfig:getPlayerInitLv(level)
    local max_lv = 1
    for _, exp in pairs(Settings) do
        if max_lv < exp.exp_lv then
            max_lv = exp.exp_lv
        end
    end
    if level > max_lv then
        return max_lv
    end
    return math.max(level, 1)
end

function ExpConfig:getMaxExp(exp_lv)
    for _, exp in pairs(Settings) do
        if tonumber(exp.exp_lv) == tonumber(exp_lv) then
            if tostring(exp.exp_max) == "###" then
                return 10000, true
            else
                return tonumber(exp.exp_max), false
            end
        end
    end
    return 10000, true
end

function ExpConfig:getLevelReward(level)
    for _, exp in pairs(Settings) do
        if tonumber(exp.exp_lv) == tonumber(level) then
            return  exp.yaoshi, exp.dress_id_list, exp.dress_num_list, exp.rune_id_list, exp.rune_num_list, exp.box_id, exp.box_num
        end
    end

    return 0, nil, nil, nil, nil, 0, 0
end

function ExpConfig:getLevelDressImg(index, level)
    for _, exp in pairs(Settings) do
        if tonumber(exp.exp_lv) == tonumber(level) then
            return tostring(exp.dress_img_list[index])
        end
    end
    return nil
end

function ExpConfig:getLevelRuneImg(index, level)
    for _, exp in pairs(Settings) do
        if tonumber(exp.exp_lv) == tonumber(level) then
            return tostring(exp.rune_img_list[index])
        end
    end
    return nil
end

function ExpConfig:getLevelBoxImg(level)
    for _, exp in pairs(Settings) do
        if tonumber(exp.exp_lv) == tonumber(level) then
            return tostring(exp.box_img)
        end
    end
    return ""
end